test("casts over an instance of SomeItem", () => {
  const theSomeItem =
    TestCommonJsonization.loadMinimalSomeItem();

  expect(
    AasTypes.isAbstractItem(theSomeItem)
  ).toStrictEqual(true);
  expect(
    AasTypes.asAbstractItem(theSomeItem)
  ).toStrictEqual(theSomeItem);

  expect(
    AasTypes.isSomeItem(theSomeItem)
  ).toStrictEqual(true);
  expect(
    AasTypes.asSomeItem(theSomeItem)
  ).toStrictEqual(theSomeItem);

  expect(
    AasTypes.isAnotherItem(theSomeItem)
  ).toStrictEqual(false);
  expect(
    AasTypes.asAnotherItem(theSomeItem)
  ).toBeNull();

  expect(
    AasTypes.isSimple(theSomeItem)
  ).toStrictEqual(false);
  expect(
    AasTypes.asSimple(theSomeItem)
  ).toBeNull();

  expect(
    AasTypes.isSomething(theSomeItem)
  ).toStrictEqual(false);
  expect(
    AasTypes.asSomething(theSomeItem)
  ).toBeNull();
});

